const input = $input.first().json;
const type = input.type || input.tipo || 'dentistas';
const specialty = input.specialty || input.especialidade || ' ';
const category = input.category || input.categoria || ' ';

return [{ json: { type, specialty, category } }];

const items = $input.all();
const records = items.filter(i => i.json.id);

if (records.length === 0) {
  return [{ json: { resultado: 'Nenhum registro encontrado.' } }];
}

const dentists = records.filter(r => r.json.record_type === 'dentista');
const procedures = records.filter(r => r.json.record_type === 'procedimento');

let resultado = '';

if (dentists.length > 0) {
  resultado += '👨‍⚕️ Dentistas disponíveis:\n';
  for (const d of dentists) {
    resultado += `  • Dr(a). ${d.json.nome} - ${d.json.detail1 || 'Clínica Geral'} (CRO: ${d.json.cro}) - ID: ${d.json.id}\n`;
    if (d.json.detail2) resultado += `    Especialidades: ${d.json.detail2}\n`;
  }
}

if (procedures.length > 0) {
  resultado += '\n🦷 Procedimentos disponíveis:\n';
  for (const p of procedures) {
    resultado += `  • ${p.json.nome} (${p.json.detail1}) - ID: ${p.json.id}\n`;
    if (p.json.price) resultado += `    💰 R$ ${parseFloat(p.json.price).toFixed(2)} | ⏱️ ${p.json.detail3}\n`;
  }
}

return [{ json: { resultado } }];
